---
cases:

    # different return type
    - base: |-
          foo(): int {
              res = 1;
              return 1;
          }
      derived: |-
          override foo(): void {
              res = 2;
          }
      expected_out: |-
        "Semantic error ESE0141: Class member foo with type undefined in Derived cannot override foo with type Int field from class Base because the overriding return type is not compatible with the other return type."

    # different arguments number 0:1
    - base: |-
          foo(): void {
              res = 1;
          }
      derived: |-
          override foo(i: int): void {
              res = 2;
          }
      expected_out: |-
        "Semantic error ESE0136: Method foo(i: Int): undefined in Derived not overriding any method"

    # different arguments number 2:1
    - base: |-
          foo(i: int, j: string): void {
              res = 1;
          }
      derived: |-
          override foo(i: int): void {
              res = 2;
          }
      expected_out: |-
        "Semantic error ESE0136: Method foo(i: Int): undefined in Derived not overriding any method"

    # same type parameters number, wrong parameters in prototype 2
    - base: |-
          foo<A, B>(i: B, j: B): void {
              res = 1;
          }
      derived: |-
          override foo<A, C>(i: A, j: A): void {
              res = 2;
          }
      expected_out: |-
        "Semantic error ESE0136: Method foo<A, C>(i: A, j: A): undefined in Derived not overriding any method"

    # same type parameters number, different parameters
    - base: |-
          foo<A, B>(i: B, j: B): void {
              res = 1;
          }
      derived: |-
          override foo<A, C>(i: A, j: C): void {
              res = 2;
          }
      expected_out: |-
        "Semantic error ESE0136: Method foo<A, C>(i: A, j: C): undefined in Derived not overriding any method"

    # different type parameters number
    - base: |-
          foo<A, B>(i: A, j: B): void {
              res = 1;
          }
      derived: |-
          override foo<B>(i: B, j: B): void {
              res = 2;
          }
      expected_out: |-
        "Semantic error ESE0136: Method foo<B>(i: B, j: B): undefined in Derived not overriding any method"

    # different type parameters number
    - base: |-
          foo(i: Number): void {
              res = 1;
          }
      derived: |-
          override foo<B>(i: Number): void {
              res = 2;
          }
      expected_out: |-
        "Semantic error ESE0136: Method foo<B>(i: Double): undefined in Derived not overriding any method"

