        interface I2<T2 extends C1> extends I1<C1> {
          foo(p: C2): T2
        }
        interface I3 extends I2<C2> {
          foo(p: C1): C3 { return new C3() }
        }

    - descr: 'Transitive overriding with generic type parameter method'
