---
cases:
  - decl: |-
        class A {}
        class B extends A {}
        class C extends A {}

        class Base {
            foo(p: B): string { return "fooB" }
            foo(p: C): string { return "fooC" }
        }

        class Derived {
            foo(p: A): string { return "fooA" }
        }

    use: |-
        function main(): void {
            let d = new Derived();
            let a = new A();
            let b = new B();
            let c = new C();
            arktest.assertEQ(d.foo(a), "fooA", "foo from Derived call expected");
            arktest.assertEQ(d.foo(b), "fooA", "foo from Derived call expected");
            arktest.assertEQ(d.foo(c), "fooA", "foo from Derived call expected");
        }
    # Spec example
  - decl: |-
        class A {}
        class B {}
        class C {
            foo(a: A): string { return "fooA" }
            foo(b: B): string { return "fooB" }
        }

        class D extends C {
            foo(o: Object): string { return "foo in D" }
        }

    use: |-
        function main(): void {
            let c: C = new D()
            arktest.assertEQ(c.foo(new A()), "foo in D", "foo from D call expected");
            arktest.assertEQ(c.foo(new B()), "foo in D", "foo from D call expected");
        }

