python3 - <<'PY'
from pathlib import Path
import yaml, re, hashlib
root=Path('/home/mbolshov/arkcompiler_runtime_core/static_core/plugins/ets/tests/ets-templates/15.semantic_rules/09.overriding/03.override-compatible_signatures')
files=sorted(root.rglob('*.yaml'))

def norm_obj(o):
    if isinstance(o, dict):
        return {k:norm_obj(v) for k,v in o.items()}
    if isinstance(o, list):
        return [norm_obj(x) for x in o]
    if isinstance(o, str):
        s='\n'.join(line.rstrip() for line in o.splitlines())
        s='\n'.join(line for line in s.splitlines() if line.strip())
        s=re.sub(r'\s+', ' ', s).strip()
        return s
    return o
buckets={}
for p in files:
    data=yaml.safe_load(p.read_text())
    norm=repr(norm_obj(data))
    h=hashlib.sha256(norm.encode()).hexdigest()
    buckets.setdefault(h, []).append(str(p))
for h, items in buckets.items():
    if len(items)>1:
        print('DUP', len(items), h)
        for path in items:
            print(' ', path)
