          foo(): void {
              res = 1;
          }
      derived: |-
          override foo(): void {
              res = 2;
          }
      call: |-
          new Derived().foo()
          arktest.assertEQ(res, 2)

    # same arguments 3:3
    - base: |-
          foo(i: int, j: string, k: number): void {
              res = 1;
          }
      derived: |-
          override foo(i: int, j: string, k: number): void {
              res = 2;
          }
      call: |-
          new Derived().foo(1, "some str", 42.0)
          arktest.assertEQ(res, 2)

    # same type parameters number
    - base: |-
          foo<A, B>(i: A, j: B): void {
              res = 1;
          }
      derived: |-
          override foo<A, B>(i: A, j: B): void {
              res = 2;
          }
      call: |-
          new Derived().foo(new Base(), new Derived())
          arktest.assertEQ(res, 2)

    # same type parameters number, same parameters in override
    - base: |-
          foo<A, B>(i: B, j: B): void {
              res = 1;
          }
      derived: |-
          override foo<A, B>(i: B, j: B): void {
              res = 2;
          }
      call: |-
          new Derived().foo<Base, Base>(new Base(), new Derived())
          arktest.assertEQ(res, 2)

